import{_ as a,o as t,c as i,a2 as s}from"./chunks/framework.CKCxdkvf.js";const p=JSON.parse('{"title":"PRD-004 — Mission Library","description":"","frontmatter":{},"headers":[],"relativePath":"prd/PRD-004.md","filePath":"prd/PRD-004.md"}'),o={name:"prd/PRD-004.md"};function r(n,e,l,h,d,c){return t(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="prd-004-—-mission-library" tabindex="-1">PRD-004 — Mission Library <a class="header-anchor" href="#prd-004-—-mission-library" aria-label="Permalink to &quot;PRD-004 — Mission Library&quot;">​</a></h1><blockquote><p>Status · Draft v0.1 Sources · 02_Project_Concept.md §mission-library · 03_Data_Catalog.md Audiences · curious learner, STEM student, contributor (PA §audiences) Promises · real mission data fully attributed, educational at every level (PA §promises) Principles · attribution is design, data over code (PA §principles) Why this is a PRD · The library is where 60 years of spaceflight become navigable. It changes what a person knows about what humanity has done in space — not just the famous missions, but the failures, the firsts, and the capability ladder that makes the next mission possible.</p></blockquote><p>A teacher is preparing a lesson on the Moon-to-Mars capability ladder. They filter to Moon missions, sort chronologically, and click Luna 9. The panel opens. &quot;First spacecraft to achieve a soft landing on another world.&quot; They click Lunokhod 1. &quot;First remote-controlled rover.&quot; They click Chandrayaan-3. &quot;First soft landing near the lunar south pole, where water ice deposits make Artemis III&#39;s target scientifically significant.&quot; The lesson writes itself.</p><h2 id="the-problem" tabindex="-1">The problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The problem&quot;">​</a></h2><p>Most people&#39;s knowledge of space exploration is three missions deep: Apollo 11, Curiosity, and whatever launched last year. The 32 missions that shaped (or will shape) the capability to reach Mars — Mariner 4 through Artemis II — and the 16 lunar predecessors that proved every technique required along the way are invisible.</p><h2 id="the-experience" tabindex="-1">The experience <a class="header-anchor" href="#the-experience" aria-label="Permalink to &quot;The experience&quot;">​</a></h2><p>The library opens on a card grid of all 32 missions (16 Mars + 16 Moon). Each card shows agency colour, mission name, type, year, and a one-line &quot;first.&quot; The filter bar at the top has DESTINATION (all, Mars, Moon), AGENCY, and STATUS (all, active, flown, planned) filters.</p><p>The user clicks a card. The detail panel slides in with the full mission record: agency, launch and arrival dates, transit time, launch vehicle, payload mass, delta-v budget. The editorial description in Crimson Pro italic tells the story of the mission. The GALLERY tab shows mission imagery from the NASA Images API. The LEARN tab has tiered links — Wikipedia for quick reference, NASA mission page for depth, peer-reviewed papers for the STEM student.</p><p>The user clicks &quot;FLY THIS MISSION.&quot; They are taken to <code>/fly?mission=curiosity</code>. The fly screen loads Curiosity&#39;s 253-day transit. They see the transfer arc. The 259-day cruise is no longer abstract.</p><h2 id="why-now" tabindex="-1">Why now <a class="header-anchor" href="#why-now" aria-label="Permalink to &quot;Why now&quot;">​</a></h2><p>The library is the archive — it doesn&#39;t require the other screens but it enriches them. Every mission in the library is flyable via the fly screen. The library is also the entry point for contributors: adding a mission means adding a JSON file and testing that it shows correctly in the library.</p><h2 id="success-looks-like" tabindex="-1">Success looks like <a class="header-anchor" href="#success-looks-like" aria-label="Permalink to &quot;Success looks like&quot;">​</a></h2><p>A user who thought they knew space exploration discovers three missions they&#39;d never heard of and can explain their significance.</p><p>The Moon capability ladder — Luna 9 → Lunokhod 1 → Luna 24 → Chandrayaan-3 — is navigable in a single filter session, and a user can articulate why each mission mattered for what came after.</p><p>A contributor adds a new mission by creating a JSON file and testing it in the library without reading any JavaScript.</p><h2 id="out-of-scope" tabindex="-1">Out of scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of scope&quot;">​</a></h2><ul><li>Sorting options beyond chronological (by agency, by delta-v, by outcome)</li><li>User notes or annotations on missions</li><li>Comparing two missions side-by-side</li><li>Missions outside the Mars and Moon destinations (v1 scope)</li></ul><h2 id="the-sharpest-threat" tabindex="-1">The sharpest threat <a class="header-anchor" href="#the-sharpest-threat" aria-label="Permalink to &quot;The sharpest threat&quot;">​</a></h2><p>The one-line &quot;first&quot; is what makes each card worth clicking. If the &quot;first&quot; is generic (&quot;first Mars orbiter&quot;) the card is a list item. If it&#39;s specific and surprising (&quot;first spacecraft to image the far side of Mars at global scale&quot;) the card earns a click. The library&#39;s value lives in the quality of that one line per mission.</p><h2 id="open-threads" tabindex="-1">Open threads <a class="header-anchor" href="#open-threads" aria-label="Permalink to &quot;Open threads&quot;">​</a></h2><ul><li>UXS-004 for full visual contract</li><li>RFC-002 for mission JSON schema</li><li>RFC-004 for <code>?dest=MARS</code> URL param</li></ul><h2 id="links" tabindex="-1">Links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;Links&quot;">​</a></h2><ul><li>Prototype: <code>docs/prototypes/P04_mission-library.html</code></li><li>Concept: <code>docs/concept/02_Project_Concept.md §mission-library</code></li></ul><hr><h2 id="extension-—-flight-params-timeline-navigator-v0-1-7" tabindex="-1">Extension — Flight params + timeline navigator (v0.1.7) <a class="header-anchor" href="#extension-—-flight-params-timeline-navigator-v0-1-7" aria-label="Permalink to &quot;Extension — Flight params + timeline navigator (v0.1.7)&quot;">​</a></h2><blockquote><p>Status · Decided · closed by ADR-027 (2026-04-29) Closes RFC-009</p></blockquote><p>The library&#39;s value lives in two surfaces this PRD didn&#39;t initially imagine: <strong>structured flight parameters</strong> per mission, and a <strong>timeline navigator</strong> that turns 28 cards into a felt history of spaceflight.</p><h3 id="what-changes" tabindex="-1">What changes <a class="header-anchor" href="#what-changes" aria-label="Permalink to &quot;What changes&quot;">​</a></h3><ul><li><strong>FLIGHT tab</strong> in the mission detail panel, alongside GALLERY and LEARN. Surfaces the new <code>flight</code> sub-object: launch C3 and declination, cruise peak speed, arrival V∞ and orbit-insertion ∆v, total mission ∆v, MET-stamped events. Each section cites its source. Missing fields render as &quot;—&quot;; sparse-data missions show a one-line caveat banner.</li><li><strong>Timeline navigator</strong> at the top of /missions: 1957 → 2030 horizontal axis, mission dots agency-coloured, two drag handles for a year window. Cards below filter to the windowed missions. Mobile = abbreviated decade strip, desktop = decade labels + agency legend. Reduced-motion users get year-pair number inputs per ADR-025.</li><li><strong><code>/fly</code> realism</strong>: when a loaded mission has <code>flight</code> data, /fly renders its actual trajectory parameters in the HUD and uses real arrival V∞ for arc geometry — two missions with the same launch and arrival dates render visibly distinct paths when their target geometry differs.</li></ul><h3 id="why-this-matters" tabindex="-1">Why this matters <a class="header-anchor" href="#why-this-matters" aria-label="Permalink to &quot;Why this matters&quot;">​</a></h3><p>The capability ladder this PRD set out to make navigable becomes felt, not just listed. A teacher scrubbing 1957 → 2024 watches the launch cadence collapse from one-per-decade to one-per-year. A student opens Curiosity&#39;s FLIGHT tab and sees C3 = 11.2 km²/s² with the press-kit citation — real, attributable, comparable.</p><p>The &quot;first&quot; line per mission stays the load-bearing card hook. The FLIGHT tab is the depth surface for users who clicked because the &quot;first&quot; earned it.</p><h3 id="honesty-rule" tabindex="-1">Honesty rule <a class="header-anchor" href="#honesty-rule" aria-label="Permalink to &quot;Honesty rule&quot;">​</a></h3><p>Sparse missions (Mars 3, Luna 9, USSR-era probes) carry <code>flight_data_quality: &quot;sparse&quot;</code> or <code>&quot;reconstructed&quot;</code>. The FLIGHT tab shows a banner; missing values stay as &quot;—&quot;. No fake numbers ever fill a gap.</p><h3 id="out-of-scope-for-v0-1-7" tabindex="-1">Out of scope for v0.1.7 <a class="header-anchor" href="#out-of-scope-for-v0-1-7" aria-label="Permalink to &quot;Out of scope for v0.1.7&quot;">​</a></h3><ul><li>Side-by-side mission comparison via the timeline (deferred — needs its own RFC if pursued).</li><li>Migration of the existing <code>delta_v</code> string field (kept as the human-readable presentation until a future deprecation slice).</li><li>Deep flight-param diff against an &quot;ideal Hohmann&quot; baseline (would belong in /plan, not /missions).</li></ul><h3 id="success-looks-like-extension" tabindex="-1">Success looks like (extension) <a class="header-anchor" href="#success-looks-like-extension" aria-label="Permalink to &quot;Success looks like (extension)&quot;">​</a></h3><p>A user drags the timeline window from 1957 → 1972, sees the Soviet lunar push beside Apollo, and clicks Luna 9 — the first soft landing — to read its sparse-but-cited flight params. The same user opens Apollo 11 in 1969 and reads the <em>measured</em> TLI ∆v alongside the MET-stamped flight events. Two missions, same FLIGHT tab structure, very different flight-data-quality story. Both honest.</p><h3 id="open-threads-resolved" tabindex="-1">Open threads (resolved) <a class="header-anchor" href="#open-threads-resolved" aria-label="Permalink to &quot;Open threads (resolved)&quot;">​</a></h3><ul><li><s>RFC-009 — Mission flight params + timeline navigator</s> closed by ADR-027</li><li>UXS-004 §Extension — visual contract for the FLIGHT tab + timeline navigator</li></ul>',40)])])}const m=a(o,[["render",r]]);export{p as __pageData,m as default};
